SELECT name 
FROM parking_lots 
WHERE capacity > 50;

SELECT name
FROM parking_lots
WHERE capacity = (SELECT MAX(capacity) FROM parking_lots);

SELECT name, capacity
FROM parking_lots
ORDER BY capacity DESC;

SELECT name, capacity
FROM parking_lots
ORDER BY capacity DESC;

SELECT parking_lot_id, SUM(available_spots) AS total_available_spots
FROM parking_lot_availability
GROUP BY parking_lot_id;
